import software.amazon.awssdk.auth.credentials.{AwsBasicCredentials, StaticCredentialsProvider}
import software.amazon.awssdk.services.s3.S3Client
import software.amazon.awssdk.services.s3.model.{CreateBucketRequest, PutObjectRequest}
import scala.util.{Failure, Success, Try}

object AwsService {
  private def loadCredentials(): AwsBasicCredentials = {
    val accessKey = sys.env.getOrElse("AWS_ACCESS_KEY_ID", throw new RuntimeException("AWS_ACCESS_KEY_ID not set"))
    val secretKey = sys.env.getOrElse("AWS_SECRET_ACCESS_KEY", throw new RuntimeException("AWS_SECRET_ACCESS_KEY not set"))
    AwsBasicCredentials.create(accessKey, secretKey)
  }

  private def createS3Client(): S3Client = {
    S3Client.builder()
      .credentialsProvider(StaticCredentialsProvider.create(loadCredentials()))
      .build()
  }

  def createBucket(bucketName: String): Try[String] = {
    val s3 = createS3Client()
    val request = CreateBucketRequest.builder().bucket(bucketName).build()

    Try(s3.createBucket(request)).map(_ => s"Bucket $bucketName created successfully").recover {
      case e: Exception => s"Failed to create bucket: ${e.getMessage}"
    }
  }

  def uploadFile(bucketName: String, key: String, filePath: String): Try[String] = {
    val s3 = createS3Client()
    val request = PutObjectRequest.builder().bucket(bucketName).key(key).build()

    Try(s3.putObject(request, java.nio.file.Paths.get(filePath))).map(_ => s"File $key uploaded to bucket $bucketName").recover {
      case e: Exception => s"Failed to upload file: ${e.getMessage}"
